SELECT DISTINCT instrument_id
FROM market_data
WHERE last = (SELECT MAX(last) FROM market_data);

SELECT DISTINCT i.ticker
FROM financial_instruments i
WHERE julianday('now') - julianday(i.last_update) > 30;

SELECT instrument_name, last_update 
FROM financial_instruments
WHERE status = 'active';

